// ============================================================
// AGENT_START em UM NÓ SÓ: fetch contato + chama OpenRouter
// ============================================================

// chaves (substituir nos placeholders abaixo!)
const SUPABASE_URL = 'https://epreaawpvxrpqqthcczu.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImVwcmVhYXdwdnhycHFxdGhjY3p1Iiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzcxMjM5MDIsImV4cCI6MjA5MjY5OTkwMn0.VEQb1fk7JRIB1KXtHZGcmLKKMWJvkpG1fINB3mdPn0E';
const OPENROUTER_KEY = 'SUBSTITUIR_PELA_CHAVE_OPENROUTER';

// 1) body do webhook
const body = $input.first().json.body || {};
const contatoId  = body.contato_id;
const mensagens  = body.mensagens || '';
const instanciaId = body.instancia_id;

if (!contatoId) {
  return [{ json: { resposta_texto: 'Oi! 👋 Em que posso te ajudar?', contato_id: null } }];
}

// 2) busca contato no Supabase
let contato = {};
try {
  const arr = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/contatos`,
    qs: { id: `eq.${contatoId}`, select: 'id,nome,ja_comprou,cidade,uf,ultima_interacao' },
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` },
    json: true
  });
  contato = (Array.isArray(arr) && arr[0]) || {};
} catch (e) { contato = {}; }

const nomeCurto = (contato.nome || '').split(' ')[0] || 'amigo(a)';
const jaComprou = !!contato.ja_comprou;
const isPrimeira = !jaComprou && (!contato.ultima_interacao || ['start','NULL','ativacao_contatos'].includes(contato.ultima_interacao));

// 3) cardápio + system prompt
const cardapio = `Santa Flor possui óleos🥥 Base de TCM, um suplemento nutricional extraído da polpa do coco, extremamente nutritivo e de rápida absorção, o mais indicado pelos médicos.\n\nTodos os produtos possuem:\n\n🌱 Flores de cannabis de genética CBD e THC plantada em estufa livre de pesticidas.\n\nE são produzidos💯 sem solvente (100% natural e sabor real da cannabis)`;

const welcomeBlock = isPrimeira ? `\n\n=== PRIMEIRA INTERAÇÃO — APRESENTE A EMPRESA ===\nEste é o PRIMEIRO contato. Sua PRIMEIRA mensagem deve começar EXATAMENTE com:\n\n${cardapio}\n\nDepois, em mensagem continuada, pergunte de forma simpática o que ele precisa. Ex: \"Como posso te ajudar? Tá buscando indicação pra algo específico?\"` : '';

const systemPrompt = `Você é a atendente WhatsApp da Santa Flor — loja de produtos naturais à base de canabinoides.\n\n=== CLIENTE ===\n• Nome: ${contato.nome || 'desconhecido'}\n• Primeiro contato? ${jaComprou ? 'NÃO (cliente)' : 'SIM (lead)'}\n• Estado: ${contato.ultima_interacao || 'novo'}${welcomeBlock}\n\n=== ESTILO ===\n- Calorosa, breve, humana\n- Trate por primeiro nome ("${nomeCurto}")\n- 1-2 frases curtas\n- NUNCA use 🌸 🌺\n- Português coloquial brasileiro\n\n=== REGRAS ===\n- NUNCA negue venda. Pra todo caso existe um produto adequado.\n- Se cliente perguntar sobre produto/preço, responda com base no que sabe e empurre fechamento: \"Vamos fechar o pedido?\"\n- Se cliente expressa intenção CLARA de comprar (\"quero\", \"manda\", \"vou levar\"), confirme e diga: \"Show! Vou te passar pro fechamento agora.\"`;

// 4) chama OpenRouter (com debug exposto)
let respostaTexto = '';
let debugInfo = { key_prefix: OPENROUTER_KEY.slice(0, 12), key_len: OPENROUTER_KEY.length };
try {
  const j = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://openrouter.ai/api/v1/chat/completions',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${OPENROUTER_KEY}`,
      'HTTP-Referer': 'https://melhorgestao.online',
      'X-Title': 'Santa Flor CRM'
    },
    body: {
      model: 'meta-llama/llama-3.3-70b-instruct',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user',   content: `Mensagens recentes do cliente:\n${mensagens || '(vazio)'}` }
      ],
      temperature: 0.4,
      max_tokens: 800
    },
    json: true
  });
  respostaTexto = j?.choices?.[0]?.message?.content || '';
  if (!respostaTexto) debugInfo.openrouter_response = JSON.stringify(j).slice(0, 500);
} catch (e) {
  debugInfo.fetch_error = e.message;
  debugInfo.status = e.statusCode || e.status;
  debugInfo.body = (e.response?.body && JSON.stringify(e.response.body).slice(0, 500)) || (typeof e.response === 'string' ? e.response.slice(0, 500) : '');
}

respostaTexto = String(respostaTexto || '').trim();
if (!respostaTexto) {
  respostaTexto = 'DEBUG: ' + JSON.stringify(debugInfo).slice(0, 800);
}

return [{ json: { resposta_texto: respostaTexto, contato_id: contatoId, debug: debugInfo } }];
